/* Speaker Avatar Background — group-chat avatar background extension for Marinara Engine */

[data-component="ChatArea.Conversation"] {
  position: relative;
  isolation: isolate;
}

[data-component="ChatArea.Conversation"] .mari-chat-area {
  background: transparent !important;
}

.speaker-avatar-bg {
  position: absolute;
  inset: 0;
  pointer-events: none;
  z-index: -1;
  overflow: hidden;
  opacity: 1;
  transition: opacity 0.6s ease;
}

.speaker-avatar-bg.is-hidden {
  opacity: 0;
}

.speaker-avatar-bg-layer {
  position: absolute;
  inset: 0;
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
  filter: blur(var(--saab-blur, 12px)) saturate(0.7);
  opacity: 0;
  transition: opacity 0.6s ease;
  will-change: opacity;
}

.speaker-avatar-bg-layer.is-active {
  opacity: var(--saab-opacity, 0.3);
}

.speaker-avatar-bg.is-reduced-motion,
.speaker-avatar-bg.is-reduced-motion .speaker-avatar-bg-layer {
  transition: none;
}

/* Settings panel (toggled with Ctrl+Shift+A or by visiting #saab) */
.speaker-avatar-bg-panel {
  position: fixed;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  z-index: 99999;
  width: 380px;
  max-width: calc(100vw - 32px);
  padding: 20px 24px;
  background: rgba(20, 20, 22, 0.96);
  color: #f0f0f0;
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 12px;
  box-shadow: 0 12px 40px rgba(0, 0, 0, 0.6);
  font-family: system-ui, -apple-system, sans-serif;
  font-size: 14px;
  line-height: 1.4;
}

.speaker-avatar-bg-panel.is-hidden { display: none; }

.speaker-avatar-bg-panel h3 {
  margin: 0 0 16px;
  font-size: 16px;
  font-weight: 600;
}

.speaker-avatar-bg-panel label {
  display: block;
  margin-bottom: 12px;
}

.speaker-avatar-bg-panel .saab-label-text {
  display: block;
  margin-bottom: 4px;
  font-size: 12px;
  font-weight: 500;
  opacity: 0.85;
}

.speaker-avatar-bg-panel input[type="range"] { width: 100%; }

.speaker-avatar-bg-panel .saab-checkbox-row {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 14px;
}

.speaker-avatar-bg-panel .saab-checkbox-row input { margin: 0; }

.speaker-avatar-bg-panel .saab-row {
  display: flex;
  gap: 8px;
  margin-top: 16px;
}

.speaker-avatar-bg-panel button {
  flex: 1;
  padding: 8px 10px;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 6px;
  color: #f0f0f0;
  font-size: 13px;
  cursor: pointer;
}

.speaker-avatar-bg-panel button:hover { background: rgba(255, 255, 255, 0.16); }

.speaker-avatar-bg-panel .saab-help {
  margin: 14px 0 0;
  font-size: 11px;
  opacity: 0.6;
  line-height: 1.5;
}

