(function () {
  // Speaker Avatar Background — renders the latest speaker's avatar as a soft,
  // blurred background in Conversation chats (1:1 and group). Browser-only,
  // DOM-driven, no API calls. Settings panel: Ctrl+Shift+A or visit #saab.

  var SURFACE_SELECTOR = '[data-component="ChatArea.Conversation"]';
  var SCROLL_SELECTOR = ".mari-messages-scroll";
  // Avatar circle wrapper class string used in both render paths: standard
  // (.mari-message-avatar) and merged group-mode (no .mari-message-avatar wrapper).
  var AVATAR_IMG_SELECTOR = "div.h-10.w-10.overflow-hidden.rounded-full img";
  var THROTTLE_MS = 150;
  var POLL_MS = 1000;

  // Persisted settings
  var KEY_ENABLED = "marinara-saab-enabled";
  var KEY_OPACITY = "marinara-saab-opacity";
  var KEY_BLUR = "marinara-saab-blur";
  var DEFAULT_OPACITY = 0.3;
  var DEFAULT_BLUR = 12;

  var reduceMotion =
    typeof window.matchMedia === "function" &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  var currentSpeaker = null, currentAvatarUrl = null;
  var activeLayer = 0, throttleTimer = null, lastSurface = null, messagesObserver = null;
  var bgRoot = null, layers = [null, null];
  var panel = null, panelLoad = null;

  function getSurface() { return document.querySelector(SURFACE_SELECTOR); }
  function getScroll() { return document.querySelector(SCROLL_SELECTOR); }

  function readOpacity() {
    var v = parseFloat(localStorage.getItem(KEY_OPACITY));
    return isFinite(v) && v >= 0 && v <= 1 ? v : DEFAULT_OPACITY;
  }
  function readBlur() {
    var v = parseFloat(localStorage.getItem(KEY_BLUR));
    return isFinite(v) && v >= 0 && v <= 50 ? v : DEFAULT_BLUR;
  }
  function readEnabled() {
    var v = localStorage.getItem(KEY_ENABLED);
    return v === null ? true : v === "true";
  }
  function setVar(name, value) { document.documentElement.style.setProperty(name, value); }
  function applyVisualSettings() {
    setVar("--saab-opacity", String(readOpacity()));
    setVar("--saab-blur", readBlur() + "px");
  }

  function speakerImages() {
    var scroll = getScroll();
    if (!scroll) return [];
    var imgs = scroll.querySelectorAll(AVATAR_IMG_SELECTOR);
    var out = [];
    for (var i = 0; i < imgs.length; i++) {
      // Skip the user persona's avatar — only assistant speakers count.
      if (imgs[i].closest(".mari-message-user")) continue;
      out.push(imgs[i]);
    }
    return out;
  }

  function findLatestSpeaker() {
    var imgs = speakerImages();
    for (var i = imgs.length - 1; i >= 0; i--) {
      var img = imgs[i];
      var url = img.src;
      if (!url) continue;
      var name = (img.alt || "").trim();
      return { name: name, avatarUrl: url };
    }
    return null;
  }

  function ensureBackground(surface) {
    if (!surface) return;
    if (bgRoot && bgRoot.parentElement === surface) return;
    teardownBackground();
    bgRoot = marinara.addElement(surface, "div", {
      class: "speaker-avatar-bg is-hidden",
      "aria-hidden": "true",
    });
    if (!bgRoot) return;
    if (reduceMotion) bgRoot.classList.add("is-reduced-motion");
    layers[0] = marinara.addElement(bgRoot, "div", { class: "speaker-avatar-bg-layer" });
    layers[1] = marinara.addElement(bgRoot, "div", { class: "speaker-avatar-bg-layer" });
  }

  function teardownBackground() {
    if (bgRoot && bgRoot.parentElement) {
      try { bgRoot.parentElement.removeChild(bgRoot); } catch (e) {}
    }
    bgRoot = null;
    layers[0] = null;
    layers[1] = null;
    activeLayer = 0;
  }

  function fadeOut() { if (bgRoot) bgRoot.classList.add("is-hidden"); }

  function applySpeaker(speaker) {
    if (!speaker || !speaker.avatarUrl) {
      fadeOut();
      currentSpeaker = speaker ? speaker.name : null;
      currentAvatarUrl = null;
      return;
    }
    if (speaker.name === currentSpeaker && speaker.avatarUrl === currentAvatarUrl) return;
    currentSpeaker = speaker.name;
    currentAvatarUrl = speaker.avatarUrl;
    var url = speaker.avatarUrl;
    var probe = new Image();
    probe.onload = function () {
      if (currentAvatarUrl !== url) return;
      if (!bgRoot || !layers[0] || !layers[1]) return;
      var next = (activeLayer + 1) % 2;
      var escaped = url.replace(/"/g, '\\"');
      layers[next].style.backgroundImage = 'url("' + escaped + '")';
      layers[next].classList.add("is-active");
      layers[activeLayer].classList.remove("is-active");
      activeLayer = next;
      bgRoot.classList.remove("is-hidden");
    };
    probe.onerror = function () { if (currentAvatarUrl === url) fadeOut(); };
    probe.src = url;
  }

  function update() {
    if (!readEnabled()) { fadeOut(); return; }
    var surface = getSurface();
    if (!surface) { fadeOut(); return; }
    ensureBackground(surface);
    applySpeaker(findLatestSpeaker());
  }

  function scheduleUpdate() {
    if (throttleTimer != null) return;
    throttleTimer = marinara.setTimeout(function () {
      throttleTimer = null;
      update();
    }, THROTTLE_MS);
  }

  function attachMessagesObserver() {
    if (messagesObserver) return;
    var target = getScroll();
    if (!target) return;
    messagesObserver = marinara.observe(target, scheduleUpdate, { childList: true, subtree: true });
  }

  function watchSurface() {
    marinara.setInterval(function () {
      var current = getSurface();
      if (current === lastSurface) return;
      lastSurface = current;
      if (messagesObserver) {
        try { messagesObserver.disconnect(); } catch (e) {}
        messagesObserver = null;
      }
      teardownBackground();
      if (!current) {
        currentSpeaker = null;
        currentAvatarUrl = null;
        return;
      }
      attachMessagesObserver();
      scheduleUpdate();
    }, POLL_MS);
  }

  function buildPanel() {
    if (panel) return;
    panel = marinara.addElement("body", "div", { class: "speaker-avatar-bg-panel is-hidden" });
    if (!panel) return;
    panel.innerHTML =
      '<h3>Speaker Avatar Background</h3>' +
      '<label class="saab-checkbox-row"><input type="checkbox" data-saab-field="enabled"> <span>Enabled</span></label>' +
      '<label><span class="saab-label-text">Opacity: <span data-saab-display="opacity"></span></span>' +
      '<input type="range" data-saab-field="opacity" min="0" max="1" step="0.01"></label>' +
      '<label><span class="saab-label-text">Blur: <span data-saab-display="blur"></span> px</span>' +
      '<input type="range" data-saab-field="blur" min="0" max="30" step="1"></label>' +
      '<div class="saab-row">' +
      '<button data-saab-action="reset">Reset</button>' +
      '<button data-saab-action="close">Close</button>' +
      '</div>' +
      '<p class="saab-help">Press Ctrl+Shift+A (or visit #saab) to reopen this panel. Settings persist in your browser.</p>';

    var qs = function (sel) { return panel.querySelector(sel); };
    var enabledEl = qs('[data-saab-field="enabled"]');
    var opacityEl = qs('[data-saab-field="opacity"]');
    var blurEl = qs('[data-saab-field="blur"]');
    var opacityDisp = qs('[data-saab-display="opacity"]');
    var blurDisp = qs('[data-saab-display="blur"]');

    function refreshDisplays() {
      opacityDisp.textContent = parseFloat(opacityEl.value).toFixed(2);
      blurDisp.textContent = blurEl.value;
    }
    panelLoad = function () {
      enabledEl.checked = readEnabled();
      opacityEl.value = readOpacity();
      blurEl.value = readBlur();
      refreshDisplays();
    };

    marinara.on(enabledEl, "change", function () {
      localStorage.setItem(KEY_ENABLED, enabledEl.checked ? "true" : "false");
      if (!enabledEl.checked) { fadeOut(); currentSpeaker = null; currentAvatarUrl = null; }
      else { update(); }
    });
    marinara.on(opacityEl, "input", function () {
      localStorage.setItem(KEY_OPACITY, opacityEl.value);
      refreshDisplays();
      applyVisualSettings();
    });
    marinara.on(blurEl, "input", function () {
      localStorage.setItem(KEY_BLUR, blurEl.value);
      refreshDisplays();
      applyVisualSettings();
    });
    marinara.on(qs('[data-saab-action="reset"]'), "click", function () {
      localStorage.removeItem(KEY_OPACITY);
      localStorage.removeItem(KEY_BLUR);
      panelLoad();
      applyVisualSettings();
    });
    marinara.on(qs('[data-saab-action="close"]'), "click", hidePanel);
  }

  function showPanel() {
    if (!panel) buildPanel();
    if (!panel || !panelLoad) return;
    panelLoad();
    panel.classList.remove("is-hidden");
  }
  function hidePanel() { if (panel) panel.classList.add("is-hidden"); }
  function togglePanel() {
    if (!panel || panel.classList.contains("is-hidden")) showPanel();
    else hidePanel();
  }

  function checkHash() {
    var h = (location.hash || "").toLowerCase();
    if (h === "#saab" || h === "#saab-settings") {
      showPanel();
      // Clean the hash so back-button behaviour and reloads stay sane.
      try {
        history.replaceState(null, "", location.pathname + location.search);
      } catch (e) {
        location.hash = "";
      }
    }
  }

  function onKeydown(e) {
    if (e.key === "Escape" && panel && !panel.classList.contains("is-hidden")) {
      hidePanel();
      return;
    }
    var key = e.key && e.key.toLowerCase();
    if (key === "a" && e.ctrlKey && e.shiftKey && !e.altKey && !e.metaKey) {
      e.preventDefault();
      togglePanel();
    }
  }

  applyVisualSettings();
  marinara.on(window, "keydown", onKeydown);
  marinara.on(window, "hashchange", checkHash);
  checkHash();
  marinara.onCleanup(teardownBackground);
  marinara.onCleanup(function () {
    var s = document.documentElement.style;
    s.removeProperty("--saab-opacity");
    s.removeProperty("--saab-blur");
  });
  lastSurface = getSurface();
  if (lastSurface) attachMessagesObserver();
  watchSurface();
  update();
})();
